// rateBookMutation / unrateBookMutation mirror the operations captured from the
// modern Goodreads Apollo client. input.rating is an int 1-5 for RateBook;
// UnrateBook clears an existing rating. The bookId is the modern GraphQL book
// node id (the legacy numeric/slug id is NOT interchangeable here).
const rateBookMutation = `mutation RateBook($input: RateBookInput!) {
  rateBook(input: $input) {
    book { id }
    rating { __typename }
  }
}`

const unrateBookMutation = `mutation UnrateBook($input: UnrateBookInput!) {
  unrateBook(input: $input) {
    book { id }
  }
}`

func newRatingCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "rating",
		Short: "Set or clear your star rating for a book (GraphQL)",
		Long: `Set or clear your star rating for a book.

Ratings are written through the modern Goodreads AWS AppSync GraphQL API
(RateBook / UnrateBook), not a legacy form. They require a bound AppSync JWT,
which is a different credential from the session cookie:

  1. Open goodreads.com logged in, open browser DevTools -> Network.
  2. Click a rating star on any book page; find the request to
     *.appsync-api.*.amazonaws.com/graphql.
  3. Copy the value of its "Authorization" request header.
  4. export GOODREADS_GRAPHQL_TOKEN='<that value>'

Writes are gated: rerun with --dry-run to preview, or set
GOODREADS_PP_ALLOW_WRITES=1 after explicit approval to execute.`,
		RunE: parentNoSubcommandRunE(flags),
	}

	cmd.AddCommand(newRatingSetCmd(flags))
	cmd.AddCommand(newRatingClearCmd(flags))
	return cmd
}

func newRatingSetCmd(flags *rootFlags) *cobra.Command {
	var stars int

	cmd := &cobra.Command{
		Use:         "set <book_id>",
		Short:       "Rate a book 1-5 stars (RateBook GraphQL mutation).",
		Example:     "  GOODREADS_GRAPHQL_TOKEN=... goodreads-pp-cli rating set kca://book/amzn1.gr.book.v1.xxxx --stars 4",
		Args:        cobra.ExactArgs(1),
		Annotations: map[string]string{"pp:endpoint": "rating.set", "pp:method": "POST", "pp:path": "graphql:RateBook", "mcp:read-only": "false"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if stars < 1 || stars > 5 {
				return usageErr(fmt.Errorf("--stars must be between 1 and 5 (got %d)", stars))
			}
			c, err := flags.newClient()
			if err != nil {
				return err
			}

			variables := map[string]any{
				"input": map[string]any{
					"bookId": args[0],
					"rating": stars,
				},
			}
			data, statusCode, err := c.GraphQL(cmd.Context(), "RateBook", rateBookMutation, variables, true)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			return emitGraphQLResult(cmd, flags, "rating", "RateBook", statusCode, data)
		},
	}
	cmd.Flags().IntVar(&stars, "stars", 0, "Star rating to set (1-5)")
	_ = cmd.MarkFlagRequired("stars")
	return cmd
}

