// emitGraphQLResult renders a GraphQL mutation result. GraphQL returns 200 OK
// even on field-level errors, so an "errors" array in the body is surfaced as a
// failure (and as a non-zero exit) rather than silently reported as success.
func emitGraphQLResult(cmd *cobra.Command, flags *rootFlags, resource, operation string, statusCode int, data json.RawMessage) error {
	var graphQLErr string
	if !flags.dryRun && len(data) > 0 {
		var parsed struct {
			Errors []struct {
				Message string `json:"message"`
			} `json:"errors"`
		}
		if json.Unmarshal(data, &parsed) == nil && len(parsed.Errors) > 0 {
			graphQLErr = parsed.Errors[0].Message
		}
	}

	if flags.asJSON || (!isTerminal(cmd.OutOrStdout()) && !flags.csv && !flags.quiet && !flags.plain) {
		envelope := map[string]any{
			"action":    "graphql",
			"resource":  resource,
			"operation": operation,
			"status":    statusCode,
			"success":   statusCode >= 200 && statusCode < 300 && graphQLErr == "",
		}
		if flags.dryRun {
			envelope["dry_run"] = true
			envelope["status"] = 0
			envelope["success"] = false
		}
		if graphQLErr != "" {
			envelope["error"] = graphQLErr
		}
		if len(data) > 0 {
			var parsed any
			if err := json.Unmarshal(data, &parsed); err == nil {
				envelope["data"] = parsed
			}
		}
		envelopeJSON, err := json.Marshal(envelope)
		if err != nil {
			return err
		}
		if perr := printOutput(cmd.OutOrStdout(), json.RawMessage(envelopeJSON), true); perr != nil {
			return perr
		}
		if graphQLErr != "" {
			return apiErr(fmt.Errorf("%s failed: %s", operation, graphQLErr))
		}
		return nil
	}
	if perr := printOutputWithFlags(cmd.OutOrStdout(), data, flags); perr != nil {
		return perr
	}
	if graphQLErr != "" {
		return apiErr(fmt.Errorf("%s failed: %s", operation, graphQLErr))
	}
	return nil
}
